    10→
    11→describe('error-utils', () => {
    12→  describe('isErrorLike', () => {
    13→    it('should return true for error-like objects', () => {
    14→      expect(isErrorLike(new Error())).toBe(true);
    15→      expect(
    16→        isErrorLike({
    17→          message: 'msg',
    18→          stack: 'stk',
    19→        }),
    20→      ).toBe(true);
    21→    });
    22→
    23→    it('should return false for non-error-like objects', () => {
    24→      expect(isErrorLike(null)).toBe(false);
    25→      expect(isErrorLike(undefined)).toBe(false);
    26→      expect(isErrorLike({})).toBe(false);
    27→      expect(isErrorLike({ message: 'msg' })).toBe(false);
    28→      expect(isErrorLike({ stack: 'stk' })).toBe(false);
    29→      expect(isErrorLike('a string')).toBe(false);
    30→      expect(isErrorLike(123)).toBe(false);
    31→    });
    32→  });
    33→
    34→  describe('assertErrorLike', () => {
    35→    it('should not throw for error-like objects', () => {
    36→      const error = new Error('test');
    37→      expect(() => assertErrorLike(error)).not.toThrow();
    38→    });
    39→
    40→    it('should throw the value if it is not error-like', () => {
    41→      const notAnError = { message: 'only message' };
    42→      try {
    43→        assertErrorLike(notAnError);
    44→      } catch (e) {
    45→        expect(e).toBe(notAnError);
    46→      }
    47→
    48→      const aString = 'a string';
    49→      expect(() => assertErrorLike(aString)).toThrow(aString);
    50→    });
    51→  });
