    57→      expect(error.message).toBe('Expected value to be defined.');
    58→    });
    59→
    60→    it('should create an error with a custom string message', () => {
    61→      // @ts-expect-error
    62→      const error = new InvariantError('Custom message', undefined);
    63→      expect(error.message).toBe('Custom message');
    64→    });
    65→
    66→    it('should create an error with a message from an object', () => {
    67→      const error = new InvariantError(
    68→        { message: 'Object message' },
    69→        // @ts-expect-error
    70→        undefined,
    71→      );
    72→      expect(error.message).toBe('Object message');
    73→    });
    74→
    75→    it('should use the provided stack from an object', () => {
    76→      const customStack = 'custom stack trace';
    77→      // @ts-expect-error
    78→      const error = new InvariantError({ stack: customStack }, undefined);
    79→      expect(error.stack).toBe(customStack);
    80→    });
