    82→    it('should use a default message if object has no message', () => {
    83→      // @ts-expect-error
    84→      const error = new InvariantError({}, undefined);
    85→      expect(error.message).toBe('Expected value to be defined.');
    86→    });
    87→
    88→    it('should capture stack trace if custom parent is provided', () => {
    89→      const originalCapture = Error.captureStackTrace;
    90→      const mockCapture = vi.fn();
    91→      Error.captureStackTrace = mockCapture;
    92→
    93→      const parentFn = () => {};
    94→      new InvariantError('test', parentFn);
